1	import mongoose from 'mongoose';
2	import { KtpCatalog } from '../models/KtpCatalog.model';
3	import { Subject } from '../models';
4	import { AppError } from '../utils';
5	import { IKtpCatalog, IKtpTopic } from '../types/roadmap.types';
