7	export interface KtpTopicInput {
8	  title: string;
9	  description?: string;
10	  order?: number;
11	  code?: string;
12	}
13	
14	/** Сортированная копия тем по order (для стабильного порядка в UI и при сборке роудмапа). */
15	function sortedTopics<T extends { order: number }>(topics: T[]): T[] {
16	  return [...topics].sort((a, b) => a.order - b.order);
17	}
