19	class KtpService {
20	  private async assertSubject(subjectId: string): Promise<void> {
21	    if (!mongoose.isValidObjectId(subjectId)) throw AppError.badRequest('Invalid subjectId');
22	    const subject = await Subject.findById(subjectId).select('_id').lean();
23	    if (!subject) throw AppError.notFound('Subject not found');
24	  }
25	
26	  /** Возвращает справочник КТП предмета (или null, если ещё не заведён). */
27	  async getCatalog(subjectId: string): Promise<IKtpCatalog | null> {
28	    await this.assertSubject(subjectId);
29	    const doc = await KtpCatalog.findOne({ subjectId }).lean<IKtpCatalog>();
30	    if (!doc) return null;
31	    doc.topics = sortedTopics(doc.topics);
32	    return doc;
33	  }
34	
35	  /** Гарантирует существование документа справочника (создаёт пустой при отсутствии). */
36	  private async ensureCatalog(subjectId: string) {
37	    const existing = await KtpCatalog.findOne({ subjectId });
38	    if (existing) return existing;
39	    return KtpCatalog.create({ subjectId: new mongoose.Types.ObjectId(subjectId), version: 1, topics: [] });
40	  }
41	
42	  async upsertMeta(subjectId: string, meta: { year?: number; version?: number }): Promise<IKtpCatalog> {
43	    await this.assertSubject(subjectId);
44	    const doc = await this.ensureCatalog(subjectId);
45	    if (typeof meta.year === 'number') doc.year = meta.year;
46	    if (typeof meta.version === 'number') doc.version = meta.version;
47	    await doc.save();
48	    return doc.toObject();
49	  }
50	
51	  async addTopic(subjectId: string, input: KtpTopicInput): Promise<IKtpCatalog> {
52	    await this.assertSubject(subjectId);
53	    const title = input.title?.trim();
54	    if (!title) throw AppError.badRequest('title is required');
55	    const doc = await this.ensureCatalog(subjectId);
56	    const nextOrder =
57	      typeof input.order === 'number'
58	        ? input.order
59	        : doc.topics.reduce((m, t) => Math.max(m, t.order + 1), 0);
60	    doc.topics.push({
61	      title,
62	      description: input.description?.trim() || undefined,
63	      order: nextOrder,
64	      code: input.code?.trim() || undefined
65	    } as IKtpTopic);
66	    await doc.save();
67	    return doc.toObject();
68	  }
69	
70	  async updateTopic(
71	    subjectId: string,
72	    topicId: string,
73	    patch: Partial<KtpTopicInput>
74	  ): Promise<IKtpCatalog> {
75	    await this.assertSubject(subjectId);
76	    if (!mongoose.isValidObjectId(topicId)) throw AppError.badRequest('Invalid КТП topicId');
77	    const doc = await KtpCatalog.findOne({ subjectId });
78	    if (!doc) throw AppError.notFound('КТП catalog not found');
79	    const topic = doc.topics.find((t) => String(t._id) === topicId);
80	    if (!topic) throw AppError.notFound('КТП topic not found');
81	    if (typeof patch.title === 'string') {
82	      const t = patch.title.trim();
83	      if (!t) throw AppError.badRequest('title cannot be empty');
84	      topic.title = t;
85	    }
86	    if (patch.description !== undefined) topic.description = patch.description.trim() || undefined;
87	    if (patch.code !== undefined) topic.code = patch.code.trim() || undefined;
88	    if (typeof patch.order === 'number') topic.order = patch.order;
89	    doc.markModified('topics');
90	    await doc.save();
91	    return doc.toObject();
92	  }
93	
94	  async deleteTopic(subjectId: string, topicId: string): Promise<IKtpCatalog> {
95	    await this.assertSubject(subjectId);
96	    if (!mongoose.isValidObjectId(topicId)) throw AppError.badRequest('Invalid КТП topicId');
97	    const doc = await KtpCatalog.findOne({ subjectId });
98	    if (!doc) throw AppError.notFound('КТП catalog not found');
99	    if (!doc.topics.some((t) => String(t._id) === topicId)) {
100	      throw AppError.notFound('КТП topic not found');
101	    }
102	    doc.set('topics', doc.topics.filter((t) => String(t._id) !== topicId));
103	    await doc.save();
104	    // NB: очистка ссылок Subject.Topic.ktpTopicIds на удалённую тему добавляется в Фазе 2.
105	    return doc.toObject();
106	  }
107	
108	  /** Переупорядочивание: orderedTopicIds — полный список id тем в нужном порядке. */
109	  async reorderTopics(subjectId: string, orderedTopicIds: string[]): Promise<IKtpCatalog> {
110	    await this.assertSubject(subjectId);
111	    const doc = await KtpCatalog.findOne({ subjectId });
112	    if (!doc) throw AppError.notFound('КТП catalog not found');
113	    const idx = new Map(orderedTopicIds.map((id, i) => [String(id), i]));
114	    doc.topics.forEach((t) => {
115	      const pos = idx.get(String(t._id));
116	      if (typeof pos === 'number') t.order = pos;
117	    });
118	    doc.markModified('topics');
119	    await doc.save();
120	    return doc.toObject();
121	  }
122	
123	  /** Массовый импорт: заменяет темы списком из payload (вставка JSON). */
124	  async importTopics(
125	    subjectId: string,
126	    payload: { topics: KtpTopicInput[]; year?: number; version?: number; replace?: boolean }
127	  ): Promise<IKtpCatalog> {
128	    await this.assertSubject(subjectId);
129	    if (!Array.isArray(payload.topics) || payload.topics.length === 0) {
130	      throw AppError.badRequest('topics array is required');
131	    }
132	    const doc = await this.ensureCatalog(subjectId);
133	    const baseOrder = payload.replace === false ? doc.topics.length : 0;
134	    const mapped = payload.topics.map((t, i) => {
135	      const title = t.title?.trim();
136	      if (!title) throw AppError.badRequest(`topics[${i}].title is required`);
137	      return {
138	        title,
139	        description: t.description?.trim() || undefined,
140	        order: typeof t.order === 'number' ? t.order : baseOrder + i,
141	        code: t.code?.trim() || undefined
142	      } as IKtpTopic;
143	    });
144	    if (payload.replace === false) {
145	      doc.topics.push(...mapped);
146	    } else {
147	      doc.set('topics', mapped);
148	    }
149	    if (typeof payload.year === 'number') doc.year = payload.year;
150	    if (typeof payload.version === 'number') doc.version = payload.version;
151	    await doc.save();
152	    return doc.toObject();
153	  }
154	}
