110	class RoadmapService {
111	  /**
112	   * Приоритет: live-сборка из КТП (КТП-справочник + маппинг тем книг).
113	   * Иначе — сохранённый в Mongo canonical (ручной JSON через upsertCanonicalAdmin).
114	   */
115	  async resolveCanonical(subjectId: string): Promise<CanonicalBundle> {
116	    if (!mongoose.isValidObjectId(subjectId)) throw AppError.badRequest('Invalid subjectId');
117	    const subject = await Subject.findById(subjectId).lean();
118	    if (!subject) throw AppError.notFound('Subject not found');
119	
120	    const ktp = await KtpCatalog.findOne({ subjectId }).lean<IKtpCatalog>();
121	    if (ktp && Array.isArray(ktp.topics) && ktp.topics.length > 0) {
122	      const ktpNodes = buildKtpCanonicalNodes(subject, ktp);
123	      if (ktpNodes.length > 0) {
124	        const sUpd = (subject as { updatedAt?: Date }).updatedAt
125	          ? new Date((subject as { updatedAt?: Date }).updatedAt as Date).getTime()
126	          : 0;
127	        const kUpd = ktp.updatedAt ? new Date(ktp.updatedAt).getTime() : 0;
128	        const version = Math.max(1, Math.floor(Math.max(sUpd, kUpd) / 1000));
129	        return { version, nodes: ktpNodes, fromChapters: true };
130	      }
131	    }
132	
133	    const doc = await CanonicalRoadmap.findOne({ subjectId }).sort({ version: -1 }).lean();
134	    if (!doc) {
135	      throw AppError.notFound('Canonical roadmap not configured for this subject');
136	    }
137	
138	    return {
139	      version: doc.version,
140	      nodes: doc.nodes as ICanonicalRoadmapNode[],
141	      description:
142	        'description' in doc && typeof doc.description === 'string' ? doc.description : undefined,
143	      sourceMeta: doc.sourceMeta,
144	      fromChapters: false
145	    };
146	  }
147	
148	  /**
149	   * Проверка перед POST /tests/generate и /tests/solo/start при roadmapNodeId в теле.
150	   */
151	  async assertKnowledgeMapTestAllowed(
152	    userId: string,
153	    subjectId: string,
154	    roadmapNodeId: string | undefined
155	  ): Promise<void> {
156	    const nid = roadmapNodeId?.trim();
157	    if (!nid) return;
158	    if (!mongoose.isValidObjectId(subjectId)) throw AppError.badRequest('Invalid subjectId');
159	    const bundle = await this.resolveCanonical(subjectId);
160	    if (!bundle.nodes.some((n) => n.nodeId === nid)) {
161	      throw AppError.badRequest('Unknown roadmapNodeId for this subject');
162	    }
163	    const raw = await UserRoadmapProgress.findOne({ userId, subjectId }).lean();
164	    const merged = this.mergeProgressWithCanonical(bundle.nodes, raw?.nodes ?? []);
165	    const p = progressMap(merged).get(nid);
166	    const count = p?.lowScoreFailCount ?? 0;
167	    if (count >= ROADMAP_MAX_KNOWLEDGE_TEST_FAILS_BEFORE_BLOCK) {
168	      throw AppError.forbidden(
169	        'По этой теме уже трижды не набрали 80%. Повторите материал и нажмите «Освоил» на странице урока, затем снова откроется тест.'
170	      );
171	    }
172	  }
173	
174	  private mergeProgressWithCanonical(
175	    canonicalNodes: ICanonicalRoadmapNode[],
176	    existingRaw: unknown[]
177	  ): IUserRoadmapNodeProgress[] {
178	    const map = new Map<string, IUserRoadmapNodeProgress>();
179	    for (const raw of existingRaw) {
180	      const n = normalizeStoredNodeProgress(raw);
181	      map.set(n.nodeId, n);
182	    }
183	    const out: IUserRoadmapNodeProgress[] = [];
184	    for (const cn of canonicalNodes) {
185	      out.push(map.get(cn.nodeId) ?? defaultProgress(cn.nodeId));
186	    }
187	    return out;
188	  }
189	
190	  async getCanonical(subjectId: string) {
191	    const bundle = await this.resolveCanonical(subjectId);
192	    const subjectOid = new mongoose.Types.ObjectId(subjectId);
193	
194	    const nodes = await Promise.all(
195	      bundle.nodes.map(async (n) => {
196	        const meta = (
197	          n.metadata && typeof n.metadata === 'object' ? n.metadata : {}
198	        ) as Record<string, unknown>;
199	        const bookId = typeof meta.bookId === 'string' ? meta.bookId : undefined;
200	        const chapterId = typeof meta.chapterId === 'string' ? meta.chapterId : undefined;
201	        const topicId = typeof meta.topicId === 'string' ? meta.topicId : undefined;
202	        let testId: string | undefined;
203	        if (bookId && chapterId) {
204	          const t = await Test.findOne({ subjectId: subjectOid, bookId, chapterId })
205	            .sort({ createdAt: -1 })
206	            .select('_id')
207	            .lean();
208	          testId = t?._id?.toString();
209	        }
210	        const chapterUrl =
211	          bookId && chapterId
212	            ? `/subjects/${subjectId}/books/${bookId}/chapters/${chapterId}${
213	                topicId ? `#topic-${topicId}` : ''
214	              }`
215	            : undefined;
216	
217	        return {
218	          nodeId: n.nodeId,
219	          title: n.title,
220	          ...(n.description?.trim() ? { description: n.description.trim() } : {}),
221	          prerequisites: n.prerequisites || [],
222	          metadata: n.metadata,
223	          ...(chapterUrl
224	            ? { chapterUrl, bookId, chapterId, ...(topicId ? { topicId } : {}) }
225	            : {}),
226	          ...(testId ? { testId } : {})
227	        };
228	      })
229	    );
230	
231	    const roadmapDescription =
232	      typeof bundle.description === 'string' ? bundle.description.trim() : '';
233	
234	    return {
235	      subjectId,
236	      version: bundle.version,
237	      ...(roadmapDescription ? { description: roadmapDescription } : {}),
238	      nodes,
239	      ...(bundle.sourceMeta ? { sourceMeta: bundle.sourceMeta } : {})
240	    };
241	  }
