284	  async getPersonalSnapshot(
285	    userId: string,
286	    subjectId: string,
287	    options?: { includeAiInsights?: boolean }
288	  ) {
289	    if (!mongoose.isValidObjectId(subjectId)) throw AppError.badRequest('Invalid subjectId');
290	    const subject = await Subject.findById(subjectId);
291	    if (!subject) throw AppError.notFound('Subject not found');
292	
293	    const bundle = await this.resolveCanonical(subjectId);
294	    const canonicalNodes = bundle.nodes;
295	
296	    let rawProgress = await UserRoadmapProgress.findOne({ userId, subjectId }).lean();
297	
298	    if (!rawProgress) {
299	      const merged = this.mergeProgressWithCanonical(canonicalNodes, []);
300	      rawProgress = await UserRoadmapProgress.findOneAndUpdate(
301	        { userId, subjectId },
302	        {
303	          $set: { canonicalVersion: bundle.version, nodes: merged },
304	          $setOnInsert: { userId, subjectId }
305	        },
306	        { upsert: true, new: true }
307	      ).lean();
308	    } else {
309	      const merged = this.mergeProgressWithCanonical(canonicalNodes, rawProgress.nodes ?? []);
310	      if (merged.length !== rawProgress.nodes.length || rawProgress.canonicalVersion !== bundle.version) {
311	        rawProgress = await UserRoadmapProgress.findOneAndUpdate(
312	          { userId, subjectId },
313	          { $set: { canonicalVersion: bundle.version, nodes: merged } },
314	          { new: true }
315	        ).lean();
316	      }
317	    }
318	
319	    const progressByNode = progressMap(
320	      this.mergeProgressWithCanonical(canonicalNodes, rawProgress!.nodes ?? [])
321	    );
322	    const mastered = masteredSet(canonicalNodes, progressByNode);
323	
324	    const viewBases: Array<
325	      Omit<IPersonalRoadmapNodeView, 'chapterUrl' | 'bookId' | 'chapterId' | 'topicId' | 'testId'> & {
326	        cn: ICanonicalRoadmapNode;
327	      }
328	    > = canonicalNodes.map((cn) => {
329	      const p = progressByNode.get(cn.nodeId)!;
330	      const availability = availabilityForNode(cn, mastered);
331	      const lowScoreFailCount = p.lowScoreFailCount ?? 0;
332	      return {
333	        cn,
334	        nodeId: cn.nodeId,
335	        title: cn.title,
336	        ...(cn.description?.trim() ? { description: cn.description.trim() } : {}),
337	        prerequisites: cn.prerequisites || [],
338	        metadata: cn.metadata,
339	        availability,
340	        mastered: p.mastered,
341	        bestScore: p.bestScore ?? 0,
342	        lowScoreFailCount,
343	        knowledgeMapTestBlocked:
344	          lowScoreFailCount >= ROADMAP_MAX_KNOWLEDGE_TEST_FAILS_BEFORE_BLOCK,
345	        isRecommended: false,
346	        recommendedPriority: 0,
347	        recommendedReason: ''
348	      };
349	    });
350	
351	    const frontier: Array<{
352	      node: ICanonicalRoadmapNode;
353	      p: IUserRoadmapNodeProgress;
354	      unlocks: number;
355	    }> = [];
356	
357	    for (const cn of canonicalNodes) {
358	      const p = progressByNode.get(cn.nodeId)!;
359	      const av = availabilityForNode(cn, mastered);
360	      if (av !== 'available') continue;
361	      if (p.mastered) continue;
362	      const unlocks = unlocksCount(cn.nodeId, canonicalNodes, mastered);
363	      frontier.push({ node: cn, p, unlocks });
364	    }
365	
366	    frontier.sort((a, b) => compareFrontier(a, b));
367	
368	    const ranked = frontier.map((f, idx) => ({
369	      ...f,
370	      priority: idx + 1,
371	      reason: reasonForNode(f.p, f.unlocks, idx === 0)
372	    }));
373	
374	    const top = ranked.slice(0, ROADMAP_TOP_K_RECOMMENDATIONS);
375	    const topIds = new Set(top.map((t) => t.node.nodeId));
376	
377	    for (const vb of viewBases) {
378	      const r = ranked.find((x) => x.node.nodeId === vb.nodeId);
379	      if (r && topIds.has(vb.nodeId)) {
380	        vb.isRecommended = true;
381	        vb.recommendedPriority = r.priority;
382	        vb.recommendedReason = r.reason;
383	      }
384	    }
385	
386	    let nextRecommended: INextRecommended | null = null;
387	    if (ranked.length > 0) {
388	      const first = ranked[0];
389	      nextRecommended = {
390	        nodeId: first.node.nodeId,
391	        reason: first.reason,
392	        priority: first.priority,
393	        topicTitle: first.node.title,
394	        subjectName: subject.title
395	      };
396	    }
397	
398	    const views: IPersonalRoadmapNodeView[] = await Promise.all(
399	      viewBases.map(async (vb) => {
400	        const { cn, ...rest } = vb;
401	        return this.enrichPersonalNodeView(subjectId, cn, rest);
402	      })
403	    );
404	
405	    const masteredTotal = views.filter((n) => n.mastered).length;
406	    const progressPercent = views.length ? Math.round((masteredTotal / views.length) * 100) : 0;
407	
408	    const base: {
409	      version: number;
410	      subjectId: string;
411	      subjectName: string;
412	      progressPercent: number;
413	      nodes: IPersonalRoadmapNodeView[];
414	      nextRecommended: INextRecommended | null;
415	      topRecommendations: Array<{
416	        nodeId: string;
417	        title: string;
418	        reason: string;
419	        priority: number;
420	      }>;
421	      ai?: { coachSummary: string; nextStepExplanation?: string };
422	    } = {
423	      version: bundle.version,
424	      subjectId,
425	      subjectName: subject.title,
426	      progressPercent,
427	      nodes: views,
428	      nextRecommended,
429	      topRecommendations: top.map((t) => ({
430	        nodeId: t.node.nodeId,
431	        title: t.node.title,
432	        reason: t.reason,
433	        priority: t.priority
434	      }))
435	    };
436	
437	    if (!options?.includeAiInsights || !process.env.OPENAI_API_KEY) {
438	      return base;
439	    }
440	
441	    try {
442	      const userDoc = await User.findById(userId).lean();
443	      const history = (userDoc?.testHistory || []).filter(
444	        (h: { subjectId?: unknown }) => String(h.subjectId) === String(subjectId)
445	      );
446	
447	      const testHistorySummary = history.slice(-20).map((h: any) => ({
448	        scorePercent: h.result?.scorePercent ?? 0,
449	        correctAnswers: h.result?.correctAnswers ?? 0,
450	        totalQuestions: h.result?.totalQuestions ?? 0,
451	        createdAt: h.createdAt ? new Date(h.createdAt).toISOString() : undefined,
452	        mistakesCount: Array.isArray(h.aiFeedback?.mistakes) ? h.aiFeedback.mistakes.length : 0
453	      }));
454	
455	      const nodesSummary = base.nodes.map((n) => ({
456	        nodeId: n.nodeId,
457	        title: n.title,
458	        availability: n.availability,
459	        mastered: n.mastered,
460	        bestScore: progressByNode.get(n.nodeId)?.bestScore ?? 0
461	      }));
462	
463	      const ai = await roadmapAIService.enrichPersonalRoadmap({
464	        subjectTitle: subject.title,
465	        nodesSummary,
466	        nextRecommended: base.nextRecommended,
467	        testHistorySummary
468	      });
469	
470	      const nodesWithHints = base.nodes.map((n) => ({
471	        ...n,
472	        ...(ai.nodeHints?.[n.nodeId] ? { aiHint: ai.nodeHints[n.nodeId] } : {})
473	      }));
474	
475	      let nr = base.nextRecommended;
476	      if (nr && ai.nextStepExplanation?.trim()) {
477	        nr = {
478	          ...nr,
479	          reason: `${nr.reason}. ${ai.nextStepExplanation.trim()}`
480	        };
481	      }
482	
483	      return {
484	        ...base,
485	        nodes: nodesWithHints,
486	        nextRecommended: nr,
487	        ai: {
488	          coachSummary: ai.coachSummary,
489	          ...(ai.nextStepExplanation ? { nextStepExplanation: ai.nextStepExplanation } : {})
490	        }
491	      };
492	    } catch (e) {
493	      console.warn('[roadmap] personal AI layer failed', e);
494	      return base;
495	    }
496	  }
