574	      nodeId: string;
575	      topicTitle: string;
576	      progressPercent: number;
577	      reason: string;
578	    }> = [];
579	    const review: Array<{
580	      subjectId: string;
581	      subjectName: string;
582	      nodeId: string;
583	      topicTitle: string;
584	      bestScore: number;
585	      lowScoreFailCount: number;
586	    }> = [];
587	
588	    for (const sid of subjectIds) {
589	      let snap;
590	      try {
591	        snap = await this.getPersonalSnapshot(userId, sid, { includeAiInsights: false });
592	      } catch {
593	        continue;
594	      }
595	      const subjectName = snap.subjectName;
596	
597	      if (snap.nextRecommended) {
598	        current.push({
599	          subjectId: sid,
600	          subjectName,
601	          nodeId: snap.nextRecommended.nodeId,
602	          topicTitle: snap.nextRecommended.topicTitle ?? '',
603	          progressPercent: snap.progressPercent,
604	          reason: snap.nextRecommended.reason
605	        });
606	      }
607	
608	      // «стоит перепройти»: есть попытки (bestScore>0), но узел слабый (< порога mastery)
609	      // ИЛИ были недавние провалы (lowScoreFailCount>0).
610	      for (const n of snap.nodes) {
611	        const weak = n.bestScore > 0 && n.bestScore < ROADMAP_KNOWLEDGE_TEST_PASS_PERCENT;
612	        const failed = (n.lowScoreFailCount ?? 0) > 0;
613	        if (weak || failed) {
614	          review.push({
615	            subjectId: sid,
616	            subjectName,
617	            nodeId: n.nodeId,
618	            topicTitle: n.title,
619	            bestScore: n.bestScore,
620	            lowScoreFailCount: n.lowScoreFailCount ?? 0
621	          });
622	        }
623	      }
624	    }
625	
626	    review.sort((a, b) => a.bestScore - b.bestScore);
627	    return { current, review };
628	  }
