651	    }
652	
653	    const list = [pair.subject1Id, pair.subject2Id];
654	    const out: IRoadmapPickerSubjectItem[] = [];
655	
656	    for (const subj of list) {
657	      const sid = subj._id?.toString();
658	      if (!sid) continue;
659	      const title = (subj.title as string) || '';
660	      const subtitle =
661	        typeof subj.description === 'string' && subj.description.trim() ? subj.description.trim() : undefined;
