667	        out.push({
668	          subjectId: sid,
669	          title,
670	          ...(subtitle ? { subtitle } : {}),
671	          roadmapConfigured: false,
672	          isRoadmapAvailable: false,
673	          progressPercent: 0,
674	          progressStatus: 'not_started',
675	          nodesTotal: 0,
676	          nodesMastered: 0
677	        });
678	        continue;
679	      }
680	
681	      if (bundle.nodes.length === 0) {
682	        out.push({
683	          subjectId: sid,
684	          title,
685	          ...(subtitle ? { subtitle } : {}),
686	          roadmapConfigured: false,
687	          isRoadmapAvailable: false,
688	          progressPercent: 0,
689	          progressStatus: 'not_started',
690	          nodesTotal: 0,
691	          nodesMastered: 0
692	        });
693	        continue;
694	      }
695	
696	      const snap = await this.getPersonalSnapshot(userId, sid, { includeAiInsights: false });
697	      const nodes = snap.nodes;
698	      const total = nodes.length;
699	      const masteredCount = nodes.filter((n) => n.mastered).length;
700	      const progressPercent = total ? Math.round((masteredCount / total) * 100) : 0;
701	
702	      const rawProg = await UserRoadmapProgress.findOne({ userId, subjectId: sid }).lean();
703	      const stored = (rawProg?.nodes ?? []).map((x) => normalizeStoredNodeProgress(x));
704	      const hasAttempts = stored.some((n) => n.bestScore > 0);
705	
706	      let progressStatus: 'not_started' | 'in_progress' | 'completed';
707	      if (total > 0 && masteredCount === total) {
708	        progressStatus = 'completed';
709	      } else if (masteredCount > 0 || hasAttempts) {
710	        progressStatus = 'in_progress';
711	      } else {
712	        progressStatus = 'not_started';
713	      }
714	
715	      out.push({
716	        subjectId: sid,
717	        title,
718	        ...(subtitle ? { subtitle } : {}),
719	        roadmapConfigured: true,
720	        isRoadmapAvailable: true,
721	        progressPercent,
722	        progressStatus,
723	        nodesTotal: total,
724	        nodesMastered: masteredCount
725	      });
726	    }
727	
728	    return out;
729	  }
