731	  /**
732	   * Пробное тестирование: отметить освоение узлов КТП (nodeId = `ktp:*`) при балле ≥ порога пробника.
733	   * Строки приходят из фанаута тем книг на КТП-узлы (computeTrialTopicMasteryRows).
734	   */
735	  async applyTrialKtpResults(
736	    userId: string,
737	    results: Array<{ subjectId: string; nodeId: string; scorePercent: number }>
738	  ): Promise<{ updatedNodeIds: string[] }> {
739	    const updatedNodeIds: string[] = [];
740	    for (const r of results) {
741	      if (!mongoose.isValidObjectId(r.subjectId)) continue;
742	      if (!isMasteredByTrialScore(r.scorePercent)) continue;
743	
744	      const bundle = await this.resolveCanonical(r.subjectId);
745	      if (!bundle.nodes.some((n) => n.nodeId === r.nodeId)) continue;
746	
747	      const existingProgress = await UserRoadmapProgress.findOne({
748	        userId,
749	        subjectId: r.subjectId
750	      }).lean();
751	      const merged = this.mergeProgressWithCanonical(bundle.nodes, existingProgress?.nodes ?? []);
752	      const pMap = progressMap(merged);
753	      const cur = pMap.get(r.nodeId) ?? defaultProgress(r.nodeId);
754	      const bestScore = Math.max(cur.bestScore, r.scorePercent);
755	      const mastered =
756	        cur.mastered || isMasteredByTrialScore(r.scorePercent) || isMasteredByBestScore(bestScore);
757	      const updated: IUserRoadmapNodeProgress = { ...cur, nodeId: r.nodeId, bestScore, mastered };
758	
759	      const finalNodes = merged.filter((n) => n.nodeId !== r.nodeId);
760	      finalNodes.push(updated);
761	      const orderedNodes = this.mergeProgressWithCanonical(bundle.nodes, finalNodes);
762	
763	      await UserRoadmapProgress.findOneAndUpdate(
764	        { userId, subjectId: r.subjectId },
765	        {
766	          $set: { canonicalVersion: bundle.version, nodes: orderedNodes },
767	          $setOnInsert: { userId, subjectId: r.subjectId }
768	        },
769	        { upsert: true, new: true }
770	      );
771	      updatedNodeIds.push(r.nodeId);
772	    }
773	    return { updatedNodeIds };
774	  }
