776	  async recordTestSubmitted(input: {
777	    userId: string;
778	    subjectId: string;
779	    nodeId: string;
780	    scorePercent: number;
781	    sessionId: string;
782	    submittedAt: Date;
783	  }) {
784	    const { userId, subjectId, nodeId, scorePercent, sessionId, submittedAt } = input;
785	
786	    if (!mongoose.isValidObjectId(subjectId)) throw AppError.badRequest('Invalid subjectId');
787	    if (!sessionId?.trim()) throw AppError.badRequest('sessionId is required');
788	
789	    const bundle = await this.resolveCanonical(subjectId);
790	    const nodeExists = bundle.nodes.some((n) => n.nodeId === nodeId);
791	    if (!nodeExists) throw AppError.badRequest('Unknown nodeId for this subject');
792	
793	    const existingAttempt = await RoadmapAttempt.findOne({ userId, sessionId });
794	    if (existingAttempt) {
795	      const snap = await this.getPersonalSnapshot(userId, subjectId);
796	      return {
797	        idempotent: true as const,
798	        updatedNodesDelta: [] as { nodeId: string; mastered: boolean }[],
799	        nextRecommended: snap.nextRecommended,
800	        topRecommendations: snap.topRecommendations
801	      };
802	    }
803	
804	    try {
805	      await RoadmapAttempt.create({
806	        userId,
807	        sessionId,
808	        subjectId,
809	        nodeId,
810	        scorePercent,
811	        submittedAt
812	      });
813	    } catch (err: unknown) {
814	      const code = (err as { code?: number })?.code;
815	      if (code === 11000) {
816	        const snap = await this.getPersonalSnapshot(userId, subjectId);
817	        return {
818	          idempotent: true as const,
819	          updatedNodesDelta: [] as { nodeId: string; mastered: boolean }[],
820	          nextRecommended: snap.nextRecommended,
821	          topRecommendations: snap.topRecommendations
822	        };
823	      }
824	      throw err;
825	    }
826	
827	    const canonicalNodes = bundle.nodes;
828	    const existingProgress = await UserRoadmapProgress.findOne({ userId, subjectId }).lean();
829	    const merged = this.mergeProgressWithCanonical(canonicalNodes, existingProgress?.nodes ?? []);
830	
831	    const pMap = progressMap(merged);
832	    const cur = pMap.get(nodeId) ?? defaultProgress(nodeId);
833	    const bestScore = Math.max(cur.bestScore, scorePercent);
834	    const mastered = cur.mastered || isMasteredByBestScore(bestScore);
835	    const prevFail = cur.lowScoreFailCount ?? 0;
836	    const lowScoreFailCount =
837	      scorePercent >= ROADMAP_KNOWLEDGE_TEST_PASS_PERCENT
838	        ? 0
839	        : Math.min(ROADMAP_MAX_KNOWLEDGE_TEST_FAILS_BEFORE_BLOCK, prevFail + 1);
840	
841	    const updated: IUserRoadmapNodeProgress = {
842	      ...cur,
843	      nodeId,
844	      bestScore,
845	      mastered,
846	      lowScoreFailCount
847	    };
848	
849	    const finalNodes = merged.filter((n) => n.nodeId !== nodeId);
850	    finalNodes.push(updated);
851	    const orderedNodes = this.mergeProgressWithCanonical(canonicalNodes, finalNodes);
852	
853	    await UserRoadmapProgress.findOneAndUpdate(
854	      { userId, subjectId },
855	      {
856	        $set: {
857	          canonicalVersion: bundle.version,
858	          nodes: orderedNodes
859	        },
860	        $setOnInsert: { userId, subjectId }
861	      },
862	      { upsert: true, new: true }
863	    ).lean();
864	
865	    const snap = await this.getPersonalSnapshot(userId, subjectId);
866	    const delta = [
867	      { nodeId, mastered: snap.nodes.find((n) => n.nodeId === nodeId)!.mastered }
868	    ];
869	
870	    return {
871	      idempotent: false as const,
872	      updatedNodesDelta: delta,
873	      nextRecommended: snap.nextRecommended,
874	      topRecommendations: snap.topRecommendations
875	    };
876	  }
