936	    nodeId: string,
937	    lessonId: string
938	  ): Promise<{ lessonId: string; readCompletedAt: string; allCompleted: boolean; nextLessonId: string | null }> {
939	    if (!mongoose.isValidObjectId(subjectId)) throw AppError.badRequest('Invalid subjectId');
940	    if (!nodeId?.trim()) throw AppError.badRequest('nodeId is required');
941	    if (!lessonId?.trim()) throw AppError.badRequest('lessonId is required');
942	
943	    const bundle = await this.resolveCanonical(subjectId);
944	    const node = bundle.nodes.find((n) => n.nodeId === nodeId);
