946	    const lessonIds = await nodeLessonIds(subjectId, node);
947	    if (!lessonIds.includes(lessonId)) throw AppError.badRequest('Unknown lessonId for this node');
948	
949	    const canonicalNodes = bundle.nodes;
950	    const raw = await UserRoadmapProgress.findOne({ userId, subjectId }).lean();
951	    const merged = this.mergeProgressWithCanonical(canonicalNodes, raw?.nodes ?? []);
952	    const map = progressMap(merged);
953	    const cur = map.get(nodeId) ?? defaultProgress(nodeId);
954	
955	    // последовательный гейтинг: все предыдущие по порядку уроки должны быть завершены
956	    const alreadyCompleted = new Set((cur.lessons ?? []).map((l) => l.lessonId));
957	    const targetIdx = lessonIds.indexOf(lessonId);
958	    for (let i = 0; i < targetIdx; i++) {
959	      if (!alreadyCompleted.has(lessonIds[i])) {
960	        throw AppError.badRequest('Сначала завершите предыдущие уроки этого узла');
961	      }
962	    }
963	
964	    const now = new Date();
965	    const lessons = [...(cur.lessons ?? [])];
966	    if (!lessons.some((l) => l.lessonId === lessonId)) {
967	      lessons.push({ lessonId, readAt: now });
968	    }
969	    const completed = new Set(lessons.map((l) => l.lessonId));
970	    const allCompleted = lessonIds.every((id) => completed.has(id));
971	    const updated: IUserRoadmapNodeProgress = {
972	      ...cur,
973	      nodeId,
974	      lessons,
975	      ...(allCompleted ? { lessonReadAt: now } : {})
976	    };
977	
978	    const finalNodes = merged.filter((n) => n.nodeId !== nodeId);
979	    finalNodes.push(updated);
980	    const orderedNodes = this.mergeProgressWithCanonical(canonicalNodes, finalNodes);
981	
982	    await UserRoadmapProgress.findOneAndUpdate(
983	      { userId, subjectId },
984	      {
985	        $set: { canonicalVersion: bundle.version, nodes: orderedNodes },
986	        $setOnInsert: { userId, subjectId }
987	      },
988	      { upsert: true, new: true }
989	    );
990	
991	    const idx = lessonIds.indexOf(lessonId);
992	    const nextLessonId = idx >= 0 && idx < lessonIds.length - 1 ? lessonIds[idx + 1] : null;
993	    return { lessonId, readCompletedAt: now.toISOString(), allCompleted, nextLessonId };
994	  }
