1036	  /**
1037	   * Админ: пересобрать (актуализировать) карту знаний из КТП.
1038	   * Проверяет, что КТП заведён и хотя бы одна тема книги замаплена; удаляет устаревший
1039	   * сохранённый снимок (live-сборка из КТП всё равно приоритетна) и обновляет `updatedAt`
1040	   * предмета — версия карты для учеников пересчитывается при следующем запросе.
1041	   */
1042	  async rebuildCanonicalFromKtp(subjectId: string): Promise<{
1043	    subjectId: string;
1044	    version: number;
1045	    nodesCount: number;
1046	  }> {
1047	    if (!mongoose.isValidObjectId(subjectId)) throw AppError.badRequest('Invalid subjectId');
1048	    const subject = await Subject.findById(subjectId).lean();
1049	    if (!subject) throw AppError.notFound('Subject not found');
1050	
1051	    const ktp = await KtpCatalog.findOne({ subjectId }).lean<IKtpCatalog>();
1052	    if (!ktp || !Array.isArray(ktp.topics) || ktp.topics.length === 0) {
1053	      throw AppError.badRequest('Сначала заведите справочник КТП по предмету (раздел «КТП»)');
1054	    }
1055	
1056	    const nodes = buildKtpCanonicalNodes(subject, ktp);
1057	    if (nodes.length === 0) {
1058	      throw AppError.badRequest(
1059	        'Ни одна тема книги не замаплена на КТП — при декомпозиции привяжите темы к темам КТП'
1060	      );
1061	    }
1062	    assertValidCanonicalNodes(nodes);
1063	
1064	    const subjectOid = new mongoose.Types.ObjectId(subjectId);
1065	    // Снимок не нужен (live-сборка приоритетна): удаляем устаревшие ручные/старые записи.
1066	    await CanonicalRoadmap.deleteMany({ subjectId: subjectOid });
1067	
1068	    const newUpdatedAt = new Date();
1069	    await Subject.findByIdAndUpdate(subjectId, { $set: { updatedAt: newUpdatedAt } });
1070	
1071	    const version = Math.max(
1072	      1,
1073	      Math.floor(Math.max(newUpdatedAt.getTime(), ktp.updatedAt ? new Date(ktp.updatedAt).getTime() : 0) / 1000)
1074	    );
1075	
1076	    return { subjectId, version, nodesCount: nodes.length };
1077	  }
1078	}
