28	/**
29	 * Строит canonical-узлы роудмапа ИЗ КТП.
30	 *
31	 * - Порядок узлов и линейные prerequisites берутся из порядка тем КТП (`order`).
32	 * - Узел = тема КТП; агрегирует ВСЕ темы книг (разных классов), замапленные на неё
33	 *   (`Subject.Topic.ktpTopicIds`), в упорядоченный список уроков (`metadata.lessons[]`).
34	 * - Темы КТП без единого источника ПРОПУСКАЮТСЯ (не рвут линейную цепочку).
35	 *
36	 * Для обратной совместимости в metadata также кладём «первичный» источник
37	 * (bookId/chapterId/topicId первой темы) и single `lesson` — их читают
38	 * getCanonical/enrichPersonalNodeView и (до Фазы 3) roadmapLesson.service.
39	 */
40	export function buildKtpCanonicalNodes(subject: unknown, ktp: IKtpCatalog): ICanonicalRoadmapNode[] {
41	  const sub = subject as SubjectShape;
42	  const subjectIdStr = sub._id?.toString();
43	  if (!subjectIdStr) return [];
44	
45	  // 1. Обратный индекс: ktpTopicId -> источники (в порядке книга → глава(order) → тема).
46	  const sourcesByKtp = new Map<string, ICanonicalNodeSource[]>();
47	  for (const book of sub.books || []) {
48	    const bid = book._id?.toString();
49	    if (!bid) continue;
50	    const chapters = [...(book.chapters || [])].sort((a, b) => (a.order ?? 0) - (b.order ?? 0));
51	    for (const ch of chapters) {
52	      const cid = ch._id?.toString();
53	      if (!cid) continue;
54	      for (const topic of ch.topics || []) {
55	        const tid = topic._id?.toString();
56	        if (!tid) continue;
57	        for (const k of topic.ktpTopicIds || []) {
58	          const key = String(k);
59	          const arr = sourcesByKtp.get(key) ?? [];
60	          arr.push({ bookId: bid, chapterId: cid, topicId: tid, title: topic.title });
61	          sourcesByKtp.set(key, arr);
62	        }
63	      }
64	    }
65	  }
66	
67	  // 2. Итерация тем КТП по порядку; узел на каждую тему с ≥1 источником.
68	  const ktpTopics = [...(ktp.topics || [])].sort((a, b) => a.order - b.order);
69	  const nodes: ICanonicalRoadmapNode[] = [];
70	  let prevNodeId: string | null = null;
71	
72	  for (const kt of ktpTopics) {
73	    const ktpTopicIdStr = kt._id?.toString();
74	    if (!ktpTopicIdStr) continue;
75	    const sources = sourcesByKtp.get(ktpTopicIdStr) ?? [];
76	    if (sources.length === 0) continue; // пропускаем пустые темы КТП — цепочка не рвётся
77	
78	    const nodeId = ktpNodeId(ktpTopicIdStr);
79	
80	    const lessons: ICanonicalNodeLesson[] = sources.map((s, i) => {
81	      const content = extractTopicText(subject, s.bookId, s.chapterId, s.topicId) || s.title || '';
82	      const summary = makeChapterSummary(content, s.title || kt.title);
83	      return {
84	        lessonId: ktpLessonId(nodeId, s.topicId),
85	        title: s.title || kt.title,
86	        order: i,
87	        content,
88	        contentFormat: 'markdown',
89	        summary,
90	        source: s
91	      };
92	    });
93	
94	    const primary = sources[0];
95	    const description = kt.description?.trim() || lessons[0]?.summary || kt.title;
96	
97	    nodes.push({
98	      nodeId,
99	      title: kt.title,
100	      description,
101	      prerequisites: prevNodeId ? [prevNodeId] : [],
102	      metadata: {
103	        subjectId: subjectIdStr,
104	        ktpTopicId: ktpTopicIdStr,
105	        sources,
106	        lessons,
107	        // первичный источник — для chapterUrl/testId в getCanonical/enrichPersonalNodeView
108	        bookId: primary.bookId,
109	        chapterId: primary.chapterId,
110	        topicId: primary.topicId,
111	        // single lesson — обратная совместимость до Фазы 3
112	        lesson: {
113	          lessonId: lessons[0].lessonId,
114	          summary: lessons[0].summary,
115	          content: lessons[0].content,
116	          contentFormat: 'markdown'
117	        }
118	      }
119	    });
120	    prevNodeId = nodeId;
121	  }
122	
123	  return nodes;
124	}
