126	/**
127	 * Тема книги (bookId/chapterId/topicId) → КТП-узлы (`ktp:*`), на которые она замаплена.
128	 * Используется для фанаута mastery из пробника на узлы КТП.
129	 */
130	export function mapBookTopicToKtpNodeIds(
131	  subject: unknown,
132	  bookId: string,
133	  chapterId: string,
134	  topicId: string
135	): string[] {
136	  const sub = subject as SubjectShape;
137	  const book = sub.books?.find((b) => b._id?.toString() === bookId);
138	  const chapter = book?.chapters?.find((c) => c._id?.toString() === chapterId);
139	  const topic = chapter?.topics?.find((t) => t._id?.toString() === topicId);
140	  const ids = (topic?.ktpTopicIds ?? []).map((x) => String(x));
141	  return ids.map((id) => ktpNodeId(id));
142	}
